const inputItem   = $input.first();
const webhookItem = $('Webhook').first();

// Texto de la oferta:
// - Si viene PDF → Extract from File1 lo extrajo en inputItem.json.text
// - Si viene oferta publicada → llega como campo de texto en el webhook
const offerText = inputItem.json.text
    || webhookItem.json.body?.offer_text
    || webhookItem.json.offer_text
    || "";

if (!offerText) {
    throw new Error("No se pudo obtener el texto de la oferta.");
}

// Binarios de los CVs:
// - Si viene PDF → Extract from File1 los pasa en inputItem.binary
// - Si viene oferta publicada → están en webhookItem.binary
const binariosInput   = inputItem.binary   || {};
const binariosWebhook = webhookItem.binary || {};

const binaries = Object.keys(binariosInput).some(k => k.startsWith('cvs'))
    ? binariosInput
    : binariosWebhook;

const cvKeys = Object.keys(binaries).filter(key => key.startsWith('cvs'));

if (cvKeys.length === 0) {
    throw new Error("No se encontraron CVs en la peticion.");
}

return cvKeys.map((key, index) => ({
    json: {
        offerText:  offerText,
        cvIndex:    index,
        cvFileName: binaries[key].fileName,
    },
    binary: {
        cv: binaries[key],
    },
}));

// =============================================================
// Nodo: Parse Analysis — compatible con Claude y Gemini Vision
// Modo: Run Once for Each Item
// =============================================================

// Claude (nodo nativo) devuelve: content[0].text
// Gemini Vision (Analyze Document) devuelve: content.parts[0].text
// Esta lógica maneja los dos formatos automáticamente.
const rawText = 
  $json.content?.[0]?.text              // Claude nativo
  || $json.content?.parts?.[0]?.text   // Gemini Vision
  || "";

if (!rawText) {
  return {
    json: {
      error: true,
      message: 'No se recibió respuesta del modelo',
      cvFileName: $('Split CVs').item.json.cvFileName,
    },
  };
}

// Limpiamos posibles bloques markdown
const cleanText = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

// Recuperamos metadatos del nodo Split CVs
const meta = $('Split CVs').item.json;

try {
  const analisis = JSON.parse(cleanText);

  return {
    json: {
      cvFileName: meta.cvFileName,
      cvIndex: meta.cvIndex,
      ...analisis,
    },
  };
} catch (e) {
  return {
    json: {
      error: true,
      message: 'JSON inválido devuelto por el modelo',
      raw: rawText,
      cvFileName: meta.cvFileName,
    },
  };
}

// =============================================================
// Nodo: Build Ranking
// Junta todos los análisis en un solo array ordenado por score
// Modo: Run Once for All Items
// =============================================================

// $input.all() devuelve TODOS los items que llegan al nodo (los 4 candidatos).
const items = $input.all();

// Extraemos solo el JSON de cada item (sin la envoltura .json).
const candidatos = items.map(item => item.json);

// Separamos los que se procesaron correctamente de los que fallaron.
const validos = candidatos.filter(c => !c.error);
const errores = candidatos.filter(c => c.error);

// Ordenamos los válidos por score_match descendente (mejor score primero).
validos.sort((a, b) => (b.score_match || 0) - (a.score_match || 0));

// Construimos la respuesta final.
// Un único item con un objeto que contiene:
//   - ranking: array ordenado con todos los candidatos
//   - total: cuántos se procesaron
//   - errores: cuántos fallaron (si los hay)
//   - timestamp: cuándo se hizo el análisis
const response = {
  ranking: validos,
  total_analizados: validos.length,
  errores: errores.length,
  detalles_errores: errores,
  timestamp: new Date().toISOString(),
};

// Devolvemos UN solo item con la respuesta completa.
return { json: response };

// =============================================================
// Nodo: Check Legibility
// Evalúa si el PDF tiene texto extraíble o es una imagen
// Modo: Run Once for Each Item
// =============================================================

// Texto extraído por el nodo Extract from PDF anterior.
const texto = $json.text || "";
const textoLimpio = texto.trim();

// Umbral: si tiene más de 150 caracteres consideramos que es legible.
// 150 es conservador: un CV con solo nombre y email ya supera eso.
// Ajusta si ves falsos positivos/negativos en tus pruebas.
const UMBRAL_LEGIBLE = 150;
const esLegible = textoLimpio.length >= UMBRAL_LEGIBLE;

// Recuperamos los metadatos del nodo Split CVs para arrastrarlos.
