// Devolvemos TODOS los datos que necesitaremos en ambas ramas.
return {
  json: {
    // Metadatos del candidato
    cvFileName: meta.cvFileName,
    cvIndex: meta.cvIndex,
    // Texto de la oferta (necesario en las dos ramas)
    offerText: meta.offerText,
    // Texto del CV (solo útil en la rama de texto)
    cvText: textoLimpio,
    // Flag de decisión
    esLegible: esLegible,
    // Info de diagnóstico (útil para depurar)
    caracteresExtraidos: textoLimpio.length,
  },
};

// =============================================================
// Nodo: Restore Binary
// Recupera el binario del CV desde el nodo Split CVs
// ya que el Switch no lo arrastra automáticamente.
// =============================================================

// Recuperamos el binario del nodo Split CVs donde se creó.
const cvBinary = $('Split CVs').item.binary.cv;

// Devolvemos el item con el JSON actual + el binario recuperado.
return {
  json: $json,
  binary: {
    cv: cvBinary,
  },
};

