const fs      = require('fs');
const path    = '/opt/recruitai/historial_candidatos.json';
const ranking = $input.first().json.ranking || [];

const rankingEtiquetado = ranking.map(c => ({
    ...c,
    // Para CVs subidos manualmente, el email viene del CV si Claude lo extrajo
    email_contacto: c.email_candidato || null,
}));

let historial = [];
try {
    const contenido = fs.readFileSync(path, 'utf8');
    historial = JSON.parse(contenido);
} catch (e) {
    historial = [];
}

const yaExistentes = new Set(
    historial.map(c => `${c.oferta}|||${c.cvFileName}`)
);

const nuevos = rankingEtiquetado.filter(c =>
    !yaExistentes.has(`${c.oferta}|||${c.cvFileName}`)
);

const actualizado = historial.concat(nuevos);
fs.writeFileSync(path, JSON.stringify(actualizado, null, 2), 'utf8');

return [{ json: { guardados: nuevos.length, total: actualizado.length } }];

// =============================================================
// Nodo: Preparar Email
// 1. Extrae el código de oferta del asunto ([OFERTA-001])
// 2. Lee la oferta correspondiente de ofertas.json
// 3. Separa los CVs adjuntos en items individuales
// =============================================================

const fs   = require('fs');
const item = $input.first();

// ── 1. Extraer código del asunto ──────────────────────────────
// El asunto debe contener algo como: [OFERTA-001] Juan Pérez
const asunto  = item.json.subject || "";
const match   = asunto.match(/\[([A-Z]+-\d+)\]/i);

if (!match) {
    throw new Error(
        `No se encontró código de oferta en el asunto: "${asunto}". ` +
        `Formato esperado: [OFERTA-001] Tu nombre`
    );
}

const codigo = match[1].toUpperCase();

// ── 2. Leer la oferta de ofertas.json ────────────────────────
let oferta;
try {
    const contenido = fs.readFileSync('/opt/recruitai/ofertas.json', 'utf8');
    const ofertas   = JSON.parse(contenido);
    oferta = ofertas.find(o => o.codigo.toUpperCase() === codigo && o.activa);
} catch (e) {
    throw new Error(`No se pudo leer ofertas.json: ${e.message}`);
}

if (!oferta) {
    throw new Error(
        `No se encontró ninguna oferta activa con el código "${codigo}". ` +
        `Comprueba que la oferta existe y está publicada en Streamlit.`
    );
}

// ── 3. Separar CVs adjuntos ───────────────────────────────────
const binaries = item.binary || {};
const cvKeys   = Object.keys(binaries).filter(key => {
    const mime = (binaries[key].mimeType || "").toLowerCase();
    const name = (binaries[key].fileName || "").toLowerCase();
    return mime.includes("pdf") || name.endsWith(".pdf");
});

if (cvKeys.length === 0) {
    throw new Error("El email no tiene CVs adjuntos en PDF.");
}

// Datos del candidato para la respuesta
const remitente = item.json.from;

// Generamos un item por cada CV
return cvKeys.map((key, index) => ({
    json: {
        offerText:    oferta.descripcion,
        ofertaTitulo: oferta.titulo,
        ofertaCodigo: oferta.codigo,
        cvIndex:      index,
        cvFileName:   binaries[key].fileName || `CV_${index + 1}.pdf`,
        remitente,
        asunto,
    },
    binary: {
        cv: binaries[key],
    },
}));

